.cdpres{display:flex;gap:7px;justify-content:center;margin-bottom:10px;}
.cdpre{padding:6px 13px;border-radius:18px;border:1.5px solid rgba(255,255,255,.25);background:transparent;color:#fff;font-size:.78rem;cursor:pointer;}
.mball{width:96px;height:96px;border-radius:50%;background:radial-gradient(circle at 35% 35%,#444,#111);margin:0 auto 11px;display:flex;align-items:center;justify-content:center;cursor:pointer;box-shadow:0 0 28px rgba(100,100,255,.45);}
.minn{width:48px;height:48px;border-radius:50%;background:radial-gradient(circle at 40% 40%,#1133ff,#000066);display:flex;align-items:center;justify-content:center;}
.mnum{color:#fff;font-size:1.15rem;font-weight:700;}
.mans{color:#a0c4ff;font-size:.88rem;text-align:center;min-height:22px;font-weight:500;}
.mball.sk{animation:sk .5s ease;}
