.abtn{padding:8px 13px;border-radius:9px;background:#ffaa00;color:#1a0533;font-weight:700;font-size:1rem;}
.tags{display:flex;flex-wrap:wrap;gap:6px;margin-bottom:11px;min-height:28px;}
.tag{background:rgba(255,255,255,.12);border-radius:18px;padding:4px 10px;color:#fff;font-size:.8rem;cursor:pointer;border:none;font-family:inherit;}
.pres{color:#ffd700;font-size:1rem;font-weight:700;text-align:center;margin-top:9px;min-height:24px;}
.rrow{display:flex;gap:7px;align-items:center;margin-bottom:11px;}
.rinp{width:68px;padding:8px 9px;border-radius:9px;border:1.5px solid rgba(255,255,255,.2);background:rgba(255,255,255,.08);color:#fff;font-size:.9rem;text-align:center;}
.rlbl{color:rgba(255,255,255,.58);font-size:.82rem;}
.rres{color:#00e5ff;font-size:2rem;font-weight:700;text-align:center;margin-top:11px;min-height:46px;font-family:monospace;}
.mgrid{display:grid;grid-template-columns:repeat(3,1fr);gap:8px;}
.mb2{padding:12px 6px;border-radius:12px;font-size:1.35rem;background:rgba(255,255,255,.08);}
.mtxt{color:#fff;font-size:.86rem;text-align:center;margin-top:9px;min-height:38px;line-height:1.5;}
.dlbar{margin-top:14px;padding-top:12px;border-top:1px solid rgba(255,255,255,.1);display:grid;grid-template-columns:1fr 1fr;gap:6px;}
.dllbl{grid-column:1/-1;text-align:center;font-size:.68rem;color:rgba(255,255,255,.32);letter-spacing:1px;}
.dlbtn{display:flex;align-items:center;gap:5px;padding:7px 10px;border-radius:9px;border:1px solid rgba(255,255,255,.14);background:rgba(255,255,255,.05);color:#fff;font-size:.7rem;font-weight:500;cursor:pointer;justify-content:center;font-family:inherit;}
