  <div class="card c3" onclick="openTool('wheel')"><div class="ci">🎡</div><div class="cl">幸运转盘</div></div>
  <div class="card c4" onclick="openTool('fireworks')"><div class="ci">🎆</div><div class="cl">烟花庆祝</div></div>
  <div class="card c5" onclick="openTool('countdown')"><div class="ci">⏱️</div><div class="cl">倒计时</div></div>
  <div class="card c6" onclick="openTool('magic8')"><div class="ci">🎱</div><div class="cl">魔法8号球</div></div>
  <div class="card c7" onclick="openTool('whopays')"><div class="ci">💸</div><div class="cl">谁来买单</div></div>
  <div class="card c8" onclick="openTool('rng')"><div class="ci">🔢</div><div class="cl">随机数字</div></div>
